#include <bits/stdc++.h>
using namespace std;
double x[10],y[10];
double d(double a1,double b1,double a2,double b2){
	double x=a2-a1,y=b2-b1;
	return sqrt(x*x+y*y);
}
int n=3; 
double a;
int main() {
	for(int i=0; i<n; i++) {
		cin>>x[i]>>y[i];
	}
	a+=d(x[0],y[0],x[1],y[1]);
	a+=d(x[1],y[1],x[2],y[2]);
	a+=d(x[0],y[0],x[2],y[2]);
	cout<<fixed<<setprecision(2)<<1.0*a;
	return 0;
}
